-- =========================================================================
-- LAMS seed data (auto-generated from the locally-cached reference data).
-- Run AFTER schema.sql AND after you have signed up (created your auth user).
-- All rows are assigned to the FIRST auth user (you). Re-running is safe
-- (on conflict do nothing). Insert order respects foreign keys.
-- =========================================================================
do $$
declare uid uuid := (select id from auth.users order by created_at limit 1);
begin
  if uid is null then
    raise exception 'No auth user found. Sign up / create your account first, then re-run this file.';
  end if;

  on conflict (id) do nothing;

  on conflict (id) do nothing;

  on conflict (id) do nothing;

  on conflict (id) do nothing;

  on conflict (id) do nothing;

end $$;
